    def maximumDetonation(self, bombs):
        n = len(bombs)
        reach = [[False] * n for _ in range(n)]
        for i in range(n):
            reach[i][i] = True
            xi, yi, ri = bombs[i]
            for j in range(n):
                if i == j:
                    continue
                xj, yj, _ = bombs[j]
                dx, dy = xi - xj, yi - yj
                if dx * dx + dy * dy <= ri * ri:
                    reach[i][j] = True
        for k in range(n):
            for i in range(n):
                if reach[i][k]:
                    for j in range(n):
                        if reach[k][j]:
                            reach[i][j] = True
        return max(sum(row) for row in reach)

