from collections import deque

class Solution:
    def maximumDetonation(self, bombs):
        n = len(bombs)
        adj = [[] for _ in range(n)]
        for i in range(n):
            xi, yi, ri = bombs[i]
            for j in range(n):
                if i == j:
                    continue
                xj, yj, _ = bombs[j]
                dx, dy = xi - xj, yi - yj
                if dx * dx + dy * dy <= ri * ri:
                    adj[i].append(j)

        def bfs(start):
            visited = {start}
            q = deque([start])
            while q:
                node = q.popleft()
                for nxt in adj[node]:
                    if nxt not in visited:
                        visited.add(nxt)
                        q.append(nxt)
            return len(visited)

        return max(bfs(i) for i in range(n))

