var maximumDetonation = function(bombs) {
    const n = bombs.length;
    const adj = Array.from({ length: n }, () => []);
    for (let i = 0; i < n; i++) {
        const [xi, yi, ri] = bombs[i];
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const [xj, yj] = bombs[j];
            const dx = xi - xj, dy = yi - yj;
            if (dx * dx + dy * dy <= ri * ri) adj[i].push(j);
        }
    }

    function bfs(start) {
        const visited = new Set([start]);
        const queue = [start];
        let head = 0;
        while (head < queue.length) {
            const node = queue[head++];
            for (const nxt of adj[node]) {
                if (!visited.has(nxt)) {
                    visited.add(nxt);
                    queue.push(nxt);
                }
            }
        }
        return visited.size;
    }

    let best = 0;
    for (let i = 0; i < n; i++) best = Math.max(best, bfs(i));
    return best;
};
